+                        lane.sort_by(|a, b| a.total_cmp(b));
+                        values.push(interpolate_percentile(&lane, fraction));
+                    }
+                }
+                Ok(Self {
+                    shape: out_shape,
+                    values,
+                    dtype: DType::F64,
+                    integer_sidecar: None,
+                })
+            }
